import{o as n,c as i,j as t,e as o,n as s,ae as r,p as d}from"./chunks/framework.BSk3HXt1.js";const p={class:"bilingual-title"},c={key:0,class:"zh-text"},h={key:1,class:"en-text"},u={class:"language-toggle-wrapper"},m={class:"language-toggle-bar"},f=JSON.parse('{"title":"「你完全值得信賴嗎？」：奧特曼正面迎戰馬斯克律師質詢 | Sam Altman vs Elon Musk Testimony","description":"山姆·奧特曼親自坐上證人席，針對誠信指控、2023年罷免案與AI掌控權的明爭暗鬥出庭作證。","frontmatter":{"title":"「你完全值得信賴嗎？」：奧特曼正面迎戰馬斯克律師質詢 | Sam Altman vs Elon Musk Testimony","description":"山姆·奧特曼親自坐上證人席，針對誠信指控、2023年罷免案與AI掌控權的明爭暗鬥出庭作證。"},"headers":[],"relativePath":"news/sam-altman-openai-vs-elon-musk-testimony.md","filePath":"news/sam-altman-openai-vs-elon-musk-testimony.md"}'),g={name:"news/sam-altman-openai-vs-elon-musk-testimony.md"},I=Object.assign(g,{setup(v){const a=d("bilingual");return(A,e)=>(n(),i("div",null,[t("h1",p,[a.value!=="en"?(n(),i("span",c,"「你完全值得信賴嗎？」：奧特曼坐上證人席，正面迎戰馬斯克律師質疑")):o("",!0),a.value!=="zh"?(n(),i("span",h,"‘Are You Completely Trustworthy?’: Musk’s Attorney Presses OpenAI CEO Sam Altman in Trial")):o("",!0)]),e[4]||(e[4]=t("div",{style:{"text-align":"center",margin:"24px 0 32px 0"}},[t("img",{src:"https://media.cnn.com/api/v1/images/stellar/prod/gettyimages-2273247036.jpg?c=16x9&q=w_800,c_fill",alt:"Sam Altman arriving at court",style:{"border-radius":"16px","max-width":"100%","box-shadow":"0 8px 32px rgba(0,0,0,0.15)",border:"1px solid rgba(255,255,255,0.08)"}})],-1)),t("div",u,[t("div",m,[t("button",{class:s(["language-toggle-btn",{active:a.value==="bilingual"}]),onClick:e[0]||(e[0]=l=>a.value="bilingual")},"中英雙語",2),t("button",{class:s(["language-toggle-btn",{active:a.value==="zh"}]),onClick:e[1]||(e[1]=l=>a.value="zh")},"純中文",2),t("button",{class:s(["language-toggle-btn",{active:a.value==="en"}]),onClick:e[2]||(e[2]=l=>a.value="en")},"純英文",2)])]),t("div",{class:s(["bilingual-article","mode-"+a.value])},[...e[3]||(e[3]=[r('<div class="bilingual-paragraph"><p class="zh-text">埃隆·馬斯克（Elon Musk）的代表律師在週二的法庭上，以一個單刀直入的問題開啟了對 OpenAI 執行長山姆·奧特曼（Sam Altman）的交叉盤問：「你完全值得信賴嗎？」</p><p class="en-text">Elon Musk’s lawyer began his cross examination of OpenAI CEO Sam Altman in court on Tuesday with a brief question: “Are you completely trustworthy?”</p></div><div class="bilingual-paragraph"><p class="zh-text">馬斯克目前正起訴這家公司及其高層，指控 OpenAI、奧特曼以及總裁格雷格·布羅克曼（Greg Brockman）在公司從非營利宗旨轉向包含營利導向結構時，違反了慈善信託原則。微軟（Microsoft）作為 OpenAI 的早期投資者，也被列為此案的共同被告。</p><p class="en-text">Musk is suing the company and its leaders over allegations that OpenAI, Altman and president Greg Brockman breached their charitable trust when OpenAI shifted from its nonprofit mission to include a profit-oriented structure. Microsoft, an early investor in OpenAI, is named as a co-defendant.</p></div><div class="bilingual-paragraph"><p class="zh-text">馬斯克的律師就 OpenAI 前董事會成員對奧特曼涉嫌「不誠實」的指控、他的個人對外投資，以及他在 2023 年那起轟動業界、短暫且充滿戲劇性的執行長罷黜案，對其進行了連番質詢。</p><p class="en-text">Musk’s lawyer grilled Altman about accusations of dishonesty from OpenAI’s board members, his investments and his brief, tumultuous ousting as CEO in 2023.</p></div><div class="bilingual-paragraph"><p class="zh-text">相較之下，OpenAI 的代表律師則暗示，曾在早期參與創辦並為該公司注資的馬斯克，從一開始就企圖取得 OpenAI 的絕對控制權，而奧特曼則據理力爭、予以抵制，以確保這項極具破壞性的強大科技不會落入單一人的獨裁統治中。</p><p class="en-text">In contrast, OpenAI’s attorney suggested Musk, who helped create and fund the company, angled early for total control of OpenAI as Altman pushed back to ensure the powerful tech was not dominated by just one person.</p></div><div class="bilingual-paragraph"><p class="zh-text">馬斯克正促請法官命令 OpenAI 回歸非營利架構，並拔除奧特曼與布羅克曼的董事會席位。他還要求將超過 1300 億美元的巨資退還回 OpenAI 的非營利主體。一旦法官的判決傾向於馬斯克，將徹底打亂 OpenAI 預計在今年底前推動的首次公開募股（IPO）計畫。</p><p class="en-text">Musk wants the judge to order OpenAI to revert to a nonprofit and for Altman and Brockman to lose their board positions. He’s also asking that more than $130 billion go back into OpenAI’s nonprofit arm. A ruling in Musk’s favor could scramble OpenAI’s plans for an initial public offering later this year.</p></div><div class="bilingual-paragraph"><p class="zh-text">OpenAI 全盤否認了馬斯克的各項指控，反駁稱馬斯克自己也曾支持成立營利結構，而他之所以提起這場官司，純粹是因為他此前在奪取 OpenAI 掌控權時失利。OpenAI 進一步指稱，馬斯克在 2018 年離開 OpenAI 後自立門戶成立了競爭對手 AI 公司，如今此舉純粹是出於打擊競爭對手的動機。</p><p class="en-text">OpenAI has denied Musk’s claims, saying Musk wanted a for-profit structure and only brought the case after he failed to gain control of OpenAI. OpenAI has claimed Musk, who started his own AI company after leaving OpenAI in 2018, is now attempting to harm a competitor.</p></div><hr><h2 class="bilingual-header"><span class="zh-text">⚖️ 誠信交鋒與 2023 年免職風雲</span><span class="en-text">Clash of Trust &amp; The 2023 Ousting Drama</span></h2><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">奧特曼否認「有預謀的欺騙」</h3><span class="dish-card-badge">焦點 1</span></div><div class="bilingual-paragraph"><p class="zh-text">馬斯克的律師史蒂芬·莫洛（Steven Molo）引用了此前 OpenAI 前董事會成員與多位前高層的證詞，指證奧特曼作風不誠實，並且在內部營造出了一種充斥著謊言的「毒性職場文化」。</p><p class="en-text">Musk attorney Steven Molo cited earlier testimony from OpenAI board members and former executives that Altman was dishonest and created a toxic culture of lying.</p></div><div class="bilingual-paragraph"><p class="zh-text">奧特曼當庭自稱為「一個誠實且值得信任的商業人仕」，但聲稱自己對部分指控並不知情。他也針對當年董事會擅自將他免職的操作手法提出了批評，認為其中「充滿了誤解」。「我當時絕對沒有試圖去欺騙董事會，」奧特曼堅定地說道。</p><p class="en-text">Altman called himself “an honest and trustworthy business person” but said he wasn’t aware of some specific accusations. Altman also criticized how the board handled his removal and said there were “misunderstandings.” “I was not trying to deceive the board,” he said.</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">昔日戰友倒戈與高層證詞</h3><span class="dish-card-badge">焦點 2</span></div><div class="bilingual-paragraph"><p class="zh-text">在庭審早些時候，OpenAI 董事會成員及高層紛紛作證陳述了對奧特曼的種種不滿，形容他強力抗拒董事會的合法監督，且在面對前技術長米拉·穆拉蒂（Mira Murati）等高層領導團隊時多有不實言論。</p><p class="en-text">OpenAI board members and executives testified about their qualms with Altman earlier in the trial, including what they described as his resistance to the board’s oversight and alleged dishonesty with senior leadership, including former Chief Technology Officer Mira Murati.</p></div><div class="bilingual-paragraph"><p class="zh-text">曾在罷黜奧特曼的決策中發揮舉足輕重作用的共同創辦人伊利亞·蘇茨克維（Ilya Sutskever）於週一作證坦承，自己曾花費數個月暗中收集證據，藉此證明奧特曼存在結構性欺瞞和管理無方的模式。儘管蘇茨克維事後投票促成奧特曼重新回歸，並表達了對自己當初行動的懊悔，但奧特曼在被驅逐後數天內旋即凱旋回歸，且原董事會也在其後徹底重組。</p><p class="en-text">OpenAI cofounder Ilya Sutskever, who played a major role in Altman’s displacement, testified on Monday that he spent months gathering evidence showing what he said was Altman’s pattern of deception and poor management. Sutskever later voted to have Altman return, saying he regretted the decision. Altman returned to his role just days after his removal and a new board was instated.</p></div><div class="bilingual-paragraph"><p class="zh-text">奧特曼在週二的庭審中，用「史詩般的背叛」、「人盡皆知」以及「極為煎熬」來形容這段歷史。「如果我早知道這段過程會有多麼地折磨與痛苦，當初我打死都不會去創立它，」奧特曼總結了他在 OpenAI 的這十年光陰。「但我依然對它心存感激，因為除了我的家人以外，這已是我此生能想像得到、最有意義的一件事了。」</p><p class="en-text">Altman described the 2023 events as an “incredible betrayal” that was “very public” and “very painful” in Tuesday’s testimony. “If I knew how difficult and painful this was going to be, I never would have tried,” Altman said of his decade at OpenAI. “I’m very grateful I didn’t, because other than my family, this has been the most meaningful thing in my life I could imagine.”</p></div></div><hr><h2 class="bilingual-header"><span class="zh-text">🌐 誰將執掌人類未來？AGI 控制權之爭</span><span class="en-text">Who Controls the Future? The Battle Over AGI Control</span></h2><div class="bilingual-paragraph"><p class="zh-text">奧特曼證稱，如何分配對「通用人工智慧（AGI）」（一種類似科幻小說、在所有學科的認知能力上都與人類平起平坐的 AI 理論性終極階段）的掌控權，正是當初創辦 OpenAI 的核心考量之一。他直言，當初之所以夥同其他共同創辦人創立這家公司，正是堅信假使有朝一日成功達成了 AGI，絕對不能允許由一個人單獨掌管它。</p><p class="en-text">Control over artificial general intelligence, a hypothetical stage of AI in which its cognitive abilities match that of a human across any subject, was an important factor in OpenAI’s founding, Altman said. The company was founded in part because Altman and the other cofounders believed one person should not be in charge of AGI if it were achieved, he said.</p></div><div class="bilingual-paragraph"><p class="zh-text">奧特曼當庭爆料，在公司早期嘗試建立營利分支時，馬斯克曾強硬索要「百分之百的絕對掌控權」，並承諾未來會隨著時間逐漸退居二線、減少影響力。但奧特曼卻極度懷疑馬斯克事後是否真的會遵守承諾放權。他以過往自身輔導無數新創公司的經歷佐證，通常極少有領導者在親自帶出一隻無敵金雞母後還願意交出權杖。「我深信馬斯克要的就是長期的牢固控制權；要是當初我們真聽了他的、同意了他所提出的公司架構，他現在早就如願以償了，」奧特曼說。</p><p class="en-text">Musk wanted “total control” of any for-profit OpenAI entity to start, Altman testified, with a promise to reduce that control over time. But Altman wasn’t convinced Musk would step back, citing his experience working with startups where leaders rarely give up power over a successful company, he said. “My belief is he wanted to have long-term control and that he would have had that had we agreed to the structure he wanted,” Altman said.</p></div><div class="bilingual-paragraph"><p class="zh-text">奧特曼更透露，共同創辦人們曾當面問了馬斯克一個發人深省的核心問題：如果由你來單獨掌控 OpenAI，那萬一某天你不幸去世，公司該交給誰？馬斯克給出的回答是他「沒怎麼認真想過這個」，但可能「會把公司傳承給我的孩子們」。奧特曼表示，馬斯克的這番回答在當時 OpenAI 草創的元老團隊中成了「令人汗毛直立的可怖瞬間」。「對此我感到非常不舒服，」奧特曼對著陪審團表示。</p><p class="en-text">OpenAI’s cofounders once asked Musk an important question: If he were to control OpenAI, what would happen to the company on his death? Musk responded that he hadn’t thought about it much and that he might pass it on to his children. Musk’s reply was a “hair-raising moment” in the early days of OpenAI, Altman said. “I didn’t feel comfortable with that,” Altman said.</p></div><div class="bilingual-paragraph"><p class="zh-text">奧特曼進一步點出，馬斯克最後會選擇在 2018 年決裂辭職，純粹是他對 OpenAI 徹底喪失了信心、壓根兒不認為這家公司能折騰出什麼名堂。根據法庭上展出的一封鐵證郵件，馬斯克曾極度悲觀地寫道：OpenAI 根本無力與 Google 旗下大名鼎鼎的 AI 科研重鎮 DeepMind 抗衡，充其量只是一只跳樑小丑。而在那段時期，Google 確實是整個人工智慧界的絕對霸主，甚至連奧特曼自己最初都差點被這家搜尋引擎巨頭的超然差距嚇到不敢踏出創業的第一步。</p><p class="en-text">Musk eventually resigned because he lost confidence in OpenAI and didn’t think it would be successful, Altman suggested. At one point, Musk wrote in an email that OpenAI wasn’t a “serious counterweight” to Google’s DeepMind AI research lab, according to evidence presented in court. Google was considered the AI leader around the time OpenAI was established. Altman almost didn’t even start OpenAI because he thought the search giant was so far ahead, he said.</p></div><div class="bilingual-paragraph"><p class="zh-text">最後，奧特曼還在庭上披露了馬斯克的一個爭議舉措：在 2018 年正式引退前，馬斯克在內部推動給所有核心研究團隊打分數、對他們的學術成就進行殘酷評級的排名舉措，導致多位關鍵科研大佬「心灰意冷、鬥志全無」，嚴重撕裂並摧毀了公司的工程師文化。奧特曼直白地總結道，馬斯克的辭職離開，在客觀上反倒大幅提振了當時整個 OpenAI 的團隊士氣。</p><p class="en-text">Before resigning from OpenAI’s board in 2018, Musk “demotivated” some key researchers by ranking their accomplishments, Altman testified, which damaged the company culture. Musk’s resignation boosted morale, Altman added.</p></div><div class="original-source-wrapper"><div class="source-label"><span class="zh-text">🌐 閱讀英文原文：</span><span class="en-text">🌐 Read Original Article:</span></div><a href="https://edition.cnn.com/2026/05/12/tech/sam-altman-openai-vs-elon-musk-testimony" target="_blank" rel="noopener noreferrer" class="source-link-btn"> CNN Tech <span style="font-size:0.8rem;">↗</span></a></div>',18)])],2)]))}});export{f as __pageData,I as default};
